private lemma unit_assemble {C : Type*} [Category C] {A B P1 PD S U : C}
    {a : A ⟶ B} {r1 : B ⟶ P1} {pbu : P1 ⟶ U} {rD : A ⟶ PD} (b : PD ⟶ P1)
    {X : PD ⟶ S} {Y : S ⟶ U}
    (hnat : a ≫ r1 = rD ≫ b) (hcore : b ≫ pbu = X ≫ Y) :
    a ≫ r1 ≫ pbu = (rD ≫ X) ≫ Y := by
  rw [← Category.assoc a, hnat, Category.assoc, hcore, ← Category.assoc]

